const pinTitle = $input.first().json.title;
const pinDesc = $input.first().json.description;
const link = $input.first().json.link;

const igCaption = `${pinTitle}\n\n${pinDesc.slice(0, 150)}...\n\nTap link in bio to discover your guardian.\n#mythicaljewelry #chinesemythology #handcrafted`;

const fbPost = `${pinDesc}\n\nShop the collection: ${link}`;

return [{
  json: {
    pinterest: { title: pinTitle, description: pinDesc, link },
    instagram: { caption: igCaption, link },
    facebook: { message: fbPost, link }
  }
}];
